solution_code:
#include <stdio.h>
#include <signal.h>

int received = 0;

void handler(int sig) {
    printf("Caught signal %d\n", sig);
    received = 1;
}

int main(void) {
    /* Installer le handler */
    signal(SIGUSR1, handler);
    printf("Handler installed\n");

    /* Envoyer le signal a soi-meme */
    raise(SIGUSR1);

    if (received)
        printf("Signal was received\n");
    else
        printf("Signal was NOT received\n");

    return 0;
}

