#include <signal.h>

/* == EXEMPLE =======================================
 * Handler pour SIGINT (Ctrl+C)
 * signal(SIGINT, handler) installe le handler
 * ================================================= */
void example_handler(int sig) {
    printf("example: caught %d\n", sig);
}
void example_signal(void) {
    signal(SIGINT, example_handler);
    printf("SIGINT handler installed\n");
    raise(SIGINT); /* se l'envoyer */
    printf("Back in main\n");
}
/* Resultat: SIGINT handler installed, example: caught 2, Back in main */

